mapper.select:
SELECT id, species, sex, birth_date, health_condition, arrival_date, status, notes, created_at, updated_at FROM hamsters
AND species = #{species}
AND sex = #{sex, typeHandler=com.ishijima.portfoliobackend.typehandler.HamsterSexTypeHandler}
AND status = #{status, typeHandler=com.ishijima.portfoliobackend.typehandler.HamsterStatusTypeHandler}
ORDER BY arrival_date DESC, id DESC
